const src = $json.body ?? $json;
const imageObj = src.image ?? null;
const rawData = String(imageObj?.data ?? src.image_base64 ?? '').trim();
const base64 = rawData.replace(/^data:[^;]+;base64,/, '');

return [
  {
    json: {
      user_id: String(src.user_id ?? ''),
      wallet_id: String(src.wallet_id ?? ''),
      category_id: src.category_id || null,
      type: String(src.type ?? 'expense'),
      amount: Number(src.amount ?? 0),
      currency: String(src.currency ?? 'VND'),
      note: String(src.note ?? ''),
      transacted_at: String(src.transacted_at ?? new Date().toISOString()),
      receipt_url: String(src.receipt_url ?? ''),
      image: {
        name: imageObj?.name ?? src.image_name ?? 'upload.jpg',
        mimeType: imageObj?.mimeType ?? src.image_mime_type ?? 'image/jpeg',
        data: base64,
      },
    },
  },
];

const request = $('Normalize Input').first().json;
const vf = $json || {};

const ocrText =
  (typeof vf.ocr_text === 'string' && vf.ocr_text.trim()) ||
  (typeof vf.raw_text === 'string' && vf.raw_text.trim()) ||
  (typeof vf.text === 'string' && vf.text.trim()) ||
  '';

const amount = Number(vf.total ?? vf.amount ?? request.amount ?? 0);
const transactedAt = vf.date || vf.invoice_date || request.transacted_at;
const vendor = (vf.vendor && (vf.vendor.name || vf.vendor)) || vf.vendor_name || '';
const suggestedCategory = request.category_id || null;
const note = String(request.note || vendor || 'Giao dịch từ OCR').trim();

return [
  {
    json: {
      user_id: request.user_id,
      wallet_id: request.wallet_id,
      category_id: suggestedCategory,
      type: request.type,
      amount,
      currency: request.currency || 'VND',
      note,
      transacted_at: transactedAt,
      receipt_url: request.receipt_url || `ocr://${request.image.name}`,
      source: 'ocr',
      is_reviewed: false,
      ocrStatus: ocrText ? 'ok' : 'empty',
      ocrText,
      vendor,
      image: request.image,
    },
  },
];

const draft = $('Build Transaction').first().json;
const transaction = $json;

return [
  {
    json: {
      ocrStatus: draft.ocrStatus,
      ocrText: draft.ocrText,
      vendor: draft.vendor,
      transaction,
      transaction_id: transaction.id,
    },
  },
];
